4	describe("nextGeneration", () => {
5	  it("should return an empty grid when given an empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single living cell with zero neighbors (underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent living cells each having only one neighbor (underpopulation)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should keep a live cell alive that has exactly two neighbors (survival)", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
19	    const sorted = result.map(([x, y]) => `${x},${y}`).sort();
20	    const expected = [[1, -1], [1, 0], [1, 1]].map(([x, y]) => `${x},${y}`).sort();
21	    expect(sorted).toEqual(expected);
22	  });
